      sidebar: "#f5f5f7",
      editor: "#ffffff",
      terminal: "#f0f0f2",
      statusBar: "#e8e8ec",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
  },
  {
    id: "t3-midnight",
