import { type Theme } from "@t3tools/shared/themes";
import { useColorTheme } from "~/hooks/useColorTheme";

interface ThemeSwatchProps {
  colors: Theme["colors"];
}

function ThemeSwatch({ colors }: ThemeSwatchProps) {
  return (
    <div
      className="flex h-8 w-14 shrink-0 overflow-hidden rounded border border-black/10"
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <div style={{ background: colors.sidebar }} className="w-[28%]" />
      {/* Main area: status bar on top, editor body below */}
      <div className="flex flex-1 flex-col">
        <div style={{ background: colors.statusBar, height: "22%" }} />
        <div style={{ background: colors.editor, flex: 1 }} />
      </div>
    </div>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((option) => {
        const selected = theme.id === option.id;
        return (
          <button
            key={option.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(option.id)}
          >
            <ThemeSwatch colors={option.colors} />
            <span className="flex min-w-0 flex-1 flex-col gap-0.5">
              <span className="text-sm font-medium">{option.name}</span>
              <span className="font-mono text-[10px] opacity-50">{option.id}</span>
            </span>
            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

