export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';
const DEFAULT_FONT_SIZE = 14;

const BUILT_IN_THEMES: Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#f0f0f2",
      accent: "#6b7ef5",
      sidebar: "#111113",
      editor: "#0d0d0f",
      terminal: "#0a0a0b",
      statusBar: "#18181c",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#1a1a1a",
      accent: "#4f5ef7",
      sidebar: "#f5f5f7",
      editor: "#ffffff",
      terminal: "#f0f0f2",
      statusBar: "#e8e8ec",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0d0f18",
      foreground: "#c8d0e0",
      accent: "#7c9ef5",
      sidebar: "#0a0c14",
      editor: "#0f1220",
      terminal: "#0d0f18",
      statusBar: "#141829",
    },
    fontFamily: DEFAULT_FONT_FAMILY,
    fontSize: DEFAULT_FONT_SIZE,
  },
];

export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((theme) => theme.id === id);
}

export function listThemes(): Theme[] {
  return BUILT_IN_THEMES;
}

export function getDefaultTheme(): Theme {
  return BUILT_IN_THEMES[0]!;
}

